#include<stdio.h>
int main(){
    int a,b,a1,b1,c1,i;
    a1=c1=b1=0;
    scanf("%d%d",&a,&b);
    for(i=1;i<=6;i++){
                      if(   ((a-i)*(a-i)) < ((b-i)*(b-i))   )a1++;

                      else if(   ((a-i)*(a-i))>((b-i)*(b-i))   )b1++;

                      else if(   ((a-i)*(a-i))==((b-i)*(b-i))  )c1++;
                      }
    printf("%d %d %d",a1,c1,b1);

    return 0;

}

