use std::cmp::Ordering;

type Pair = (i8, i8);
fn input_pair() -> Pair {
    let mut buf = String::new();
    std::io::stdin().read_line(&mut buf).unwrap();
    let buf: Vec<i8> = buf
        .trim()
        .split_whitespace()
        .map(|elem| elem.parse().unwrap())
        .collect();
    (buf[0], buf[1])
}

fn main() {
    let (a, b) = input_pair();
    let (mut a_count, mut b_count, mut mid) = (0, 0, 0);

    for i in 1..=6 {
        match (a-i).abs().cmp(&(b-i).abs()) {
            Ordering::Less => a_count += 1,
            Ordering::Greater => b_count += 1,
            Ordering::Equal => mid += 1
        }
    }

    print!("{} {} {}", a_count, mid, b_count);
}
